SELECT blr.id AS id, blr.school_year AS schoolYear, ss.id AS semesterId, ss.name AS semesterName, grade.id AS classGroupId, grade.grade_group_name AS classGroupName, cla.id AS classId, cla.class_name AS className, blr.student_id AS studentId, stu.chinese_name AS studentName, blr.registration_date AS registrationDate, blr.type AS type, blr.registration_id AS registrationId, blr.registration_content AS registrationContent, blr.registrant AS registrant FROM big_little_rest blr LEFT JOIN student_info stu ON stu.id = blr.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_semester ss on blr.semester_id = ss.id WHERE blr.deleted = 0
AND blr.school_id = #{reqModel.schoolId}
AND blr.school_year = #{reqModel.schoolYear}
AND blr.semester_id = #{reqModel.semesterId}
AND blr.class_id = #{reqModel.classId}
AND blr.student_id = #{reqModel.studentId}
AND blr.registration_date >= #{reqModel.startDate}
AND blr.registration_date <= #{reqModel.endDate}
AND blr.class_id IN
#{item}
ORDER BY blr.create_time desc
